package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers",
		"--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin via a pipe
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Capture jq's stdout and stderr
	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	// Capture aliyun's stderr
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process
		aliyunCmd.Process.Kill()
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Close the read end of the pipe in the parent after jq has started,
	// so that aliyun gets a SIGPIPE if jq exits early
	aliyunStdout.(io.Closer).Close()

	// Wait for both commands to finish
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	output := jqStdout.String()

	if aliyunErr != nil {
		return output, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		return output, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	// Write the output to the specified file
	if err := os.WriteFile(outputFile, []byte(output), 0644); err != nil {
		return output, fmt.Errorf("failed to write output file: %w", err)
	}

	return output, nil
}

func main() {
	output, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(output)
}

