package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the content written to the output file and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>&;'\"\\") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}
	if strings.ContainsAny(outputFile, "`$\n\r\t|>&;'\"\\") {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Build the pipeline: aliyun command | jq filter > output file
	cmdStr := fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName '%s' | jq '.LoadBalancers.LoadBalancer[]' > '%s'",
		loadBalancerName, outputFile)

	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture stderr for error reporting; stdout is redirected to the file by the shell
	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return "", fmt.Errorf("command failed: %w, stderr: %s", err, stderr.String())
	}

	// Read the output file to return its content
	data, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(data), nil
}

func main() {
	result, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Result:\n%s\n", result)
}

