	// Create the aliyun command — no shell involved, arguments passed directly
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers",
		"--LoadBalancerName", loadBalancerName)

	// Create the jq command — no shell involved
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin using a pipe
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
