package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the aliyun command with arguments passed directly (no shell injection risk)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers",
		"--LoadBalancerName", loadBalancerName)

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin via a pipe
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Capture jq's stdout and stderr
	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	// Capture aliyun's stderr
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to finish
	aliyunErr := aliyunCmd.Wait()

	// Wait for jq command to finish
	jqErr := jqCmd.Wait()

	outputStr := jqStdout.String()

	// Check for errors from aliyun command
	if aliyunErr != nil {
		return outputStr, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}

	// Check for errors from jq command
	if jqErr != nil {
		return outputStr, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	// Write the output to the specified file
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		return outputStr, fmt.Errorf("failed to write output file: %w", err)
	}

	return outputStr, nil
}

func main() {
	result, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Result: %s\n", result)
}

