func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Connect aliyun stdout to jq stdin via pipe
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdin = pipe
	jqCmd.Stdout = outFile

	// Capture stderr from both commands
	var aliyunStderr, jqStderr []byte
	aliyunStderrPipe, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stderr pipe: %w", err)
	}
	jqStderrPipe, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stderr pipe: %w", err)
	}

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read stderr
	aliyunStderr, _ = io.ReadAll(aliyunStderrPipe)
	jqStderr, _ = io.ReadAll(jqStderrPipe)

	// Wait for both commands to finish
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, string(aliyunStderr))
	}

	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, string(jqStderr))
	}

	// Read the output file to return its content
	outFile.Seek(0, 0)
	content, err := io.ReadAll(outFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	result := string(content)
	return result, nil
}

func main() {
	loadBalancerName := "my-slb"
	outputFile := "output.json"

	if len(os.Args) >= 3 {
		loadBalancerName = os.Args[1]
		outputFile = os.Args[2]
	} else if len(os.Args) >= 2 {
		loadBalancerName = os.Args[1]
	}

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
