package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create the pipe between aliyun and jq
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe from aliyun command: %w", err)
	}

	jqCmd.Stdin = pipe

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()

	// Capture jq output to both file and a buffer for returning
	pr, pw := io.Pipe()
	jqCmd.Stdout = io.MultiWriter(outFile, pw)

	// Capture stderr for error reporting
	var jqStderrBuf []byte
	jqCmd.Stderr = os.Stderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read output in a goroutine
	resultCh := make(chan string)
	errCh := make(chan error)
	go func() {
		data, err := io.ReadAll(pr)
		if err != nil {
			errCh <- err
			return
		}
		resultCh <- string(data)
	}()

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		pw.Close()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		pw.Close()
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(jqStderrBuf))
	}

	// Close the pipe writer to signal EOF to the reader
	pw.Close()

	// Get the result
	select {
	case result := <-resultCh:
		return result, nil
	case err := <-errCh:
		return "", fmt.Errorf("failed to read output: %w", err)
	}
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("Command executed successfully.")
	fmt.Println("Output:")
	fmt.Println(result)
	fmt.Printf("Results also written to: %s\n", outputFile)
}

